import numpy as np

def target_network_update(
    online_params: list,
    target_params: list,
    tau: float = 0.005,
    update_type: str = 'soft'
) -> list:
    if update_type == 'hard':
        return [param.copy() for param in online_params]
    elif update_type == 'soft':
        return [
            tau * online + (1.0 - tau) * target
            for online, target in zip(online_params, target_params)
        ]
    else:
        raise ValueError(f"Unknown update_type: '{update_type}'. Use 'soft' or 'hard'.")

