import numpy as np

def target_network_update(
    online_params: list,
    target_params: list,
    tau: float = 0.005,
    update_type: str = 'soft'
) -> list:
    if update_type == 'hard':
        return [np.copy(p) for p in online_params]
    elif update_type == 'soft':
        updated = []
        for online, target in zip(online_params, target_params):
            # In-place blend: avoids allocating a third temporary array
            new_target = np.empty_like(target)
            np.multiply(online, tau, out=new_target)
            np.multiply(target, 1.0 - tau, out=target)  # reuse target buffer
            np.add(new_target, target, out=new_target)
            updated.append(new_target)
        return updated
    else:
        raise ValueError(f"Unknown update_type: '{update_type}'. Use 'soft' or 'hard'.")


# --- Vectorized version using np.lerp for clarity ---
def target_network_update_lerp(
    online_params: list,
    target_params: list,
    tau: float = 0.005,
    update_type: str = 'soft'
) -> list:
    """Cleaner version using np.lerp: lerp(a, b, t) = a + t*(b-a) = (1-t)*a + t*b.
    Note: np.lerp(target, online, tau) gives (1-tau)*target + tau*online."""
    if update_type == 'hard':
        return [np.copy(p) for p in online_params]
    return [
        np.lerp(target, online, tau)
        for online, target in zip(online_params, target_params)
    ]
